struct stat_double { double mystery; double a; double b; };

void compute(stat_double &d) {
  d.mystery = d.a + d.b;
}

int main() {
  stat_double d;
  d.a = 3; d.b = 4;
  compute(d);
  cout << d.mystery << endl;
  return 0;
}

struct stat_double { double mystery; double a; double b; };

void who_am_i(stat_double &data) {
  data.mystery = 0;
  if (data.a > data.b) {
    data.mystery = data.a;
  } else {
    data.mystery = data.b;
  }
}

// Q2 spec: book has id, title, price.

struct book {
  int id;
  string title;
  double price;
};

void read_book(book &list[], int count) {
  for (int i = 0; i < count; i++) {
    cout << "id: ";    cin >> list[i].id;
    cout << "title: "; cin >> list[i].title;
    cout << "price: "; cin >> list[i].price;
  }
}

int main() {
  const int MAX = 100;
  book list[MAX];
  int count;
  cin >> count;
  read_book(list, count);
  for (int i = 0; i < count; i++) {
    printf("%d %s %.2f\n", list[i].id, list[i].title.c_str(), list[i].price);
  }
  return 0;
}

